using System.Collections;

/// <summary>
/// Activa o clima manual: fixa o clima neste valor e ignora alterações
/// automáticas até Action_DisableManualWeather ser executada (que restaura o
/// clima de antes desta ação). Útil para zonas onde não se quer interferência
/// do clima global, ou que precisam de um clima específico (Etapa 8).
/// </summary>
[System.Serializable]
public class Action_SetManualWeather : NpcAction
{
    public WeatherType weather = WeatherType.Limpo;

    public override IEnumerator Execute(NpcController npc)
    {
        WorldState.Instance?.SetManualWeather(weather);
        yield break;
    }
}

/// <summary>Desactiva o clima manual, restaurando o clima de antes de Action_SetManualWeather.</summary>
[System.Serializable]
public class Action_DisableManualWeather : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        WorldState.Instance?.DisableManualWeather();
        yield break;
    }
}

/// <summary>
/// Activa a hora manual: fixa a hora do dia neste valor e ignora o
/// DayNightCycle2D até Action_DisableManualTimeOfDay ser executada (que
/// restaura a hora de antes desta ação, e deixa o ciclo dia/noite voltar a
/// correr normalmente). Útil para zonas que precisam de um horário específico
/// (Etapa 8).
/// </summary>
[System.Serializable]
public class Action_SetManualTimeOfDay : NpcAction
{
    public TimeOfDay timeOfDay = TimeOfDay.Manha;

    public override IEnumerator Execute(NpcController npc)
    {
        WorldState.Instance?.SetManualTimeOfDay(timeOfDay);
        yield break;
    }
}

/// <summary>Desactiva a hora manual, restaurando a hora de antes de Action_SetManualTimeOfDay e devolvendo o controlo ao DayNightCycle2D.</summary>
[System.Serializable]
public class Action_DisableManualTimeOfDay : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        WorldState.Instance?.DisableManualTimeOfDay();
        yield break;
    }
}
